"""Candidate controller for SD3.5 PickScore discovery."""

from __future__ import annotations

from flow_autotts.core.env import FlowTTSEnv
from flow_autotts.core.errors import BudgetExceededError, InvalidActionError
from flow_autotts.core.state import AnswerRecord, PreviewRecord


class OptimalController:
    """Beta-scheduled scout, confirm, prune, and selective backward refine."""

    def solve(self, env: FlowTTSEnv, beta: float) -> AnswerRecord:
        beta = min(max(float(beta), 0.0), 1.0)
        if beta <= 0.0:
            return self._deterministic_anchor(env)

        schedule = self._schedule(beta, env)
        scout_cost = self._steps_to(env, 0.0, schedule["first_probe_time"]) + 1
        scout_count = max(1, min(schedule["scouts"], self._budget_cap(env, scout_cost)))

        root_ids = env.spawn(scout_count)
        try:
            self._advance_many(env, root_ids, schedule["first_probe_time"])
            self._preview_many(env, root_ids)
        except (BudgetExceededError, InvalidActionError):
            return self._fallback_answer(env)

        ranked = self._ranked_previews(env)
        if not ranked:
            return self._fallback_answer(env)

        keep_count = self._keep_count(beta, ranked, schedule)
        keep_ids = {preview.particle_id for preview in ranked[:keep_count]}
        self._prune_active(env, root_ids, keep_ids)

        confirm_ids = [pid for pid in root_ids if pid in keep_ids and self._is_active(env, pid)]
        if confirm_ids and schedule["second_probe_time"] > schedule["first_probe_time"]:
            try:
                self._advance_many(env, confirm_ids, schedule["second_probe_time"])
                self._preview_many(env, confirm_ids)
            except (BudgetExceededError, InvalidActionError):
                return self._fallback_answer(env)

        ranked = self._ranked_previews(env)
        if not ranked:
            return self._fallback_answer(env)

        finish_count = min(len(ranked), self._finish_count(beta, ranked, schedule))
        finish_ids = [preview.particle_id for preview in ranked[:finish_count]]
        self._prune_active(env, root_ids, set(finish_ids))
        self._finish_and_preview(env, finish_ids)

        ranked = self._ranked_previews(env)
        if not ranked:
            return self._fallback_answer(env)

        if beta >= schedule["branch_min_beta"] and env.budget_left > 0:
            self._branch_and_refine(env, ranked, schedule, beta)

        return env.answer(rule="best_preview_score")

    def _deterministic_anchor(self, env: FlowTTSEnv) -> AnswerRecord:
        root_id = env.spawn(1)[0]
        try:
            self._finish_to(env, root_id, 1.0)
        except (BudgetExceededError, InvalidActionError):
            pass
        return env.answer(rule="latest_active")

    def _schedule(self, beta: float, env: FlowTTSEnv) -> dict[str, float | int]:
        last_idx = max(1, len(env.time_grid) - 1)
        return {
            "scouts": 1
            + int(beta > 0.0)
            + int(beta >= 0.33)
            + int(beta >= 0.66)
            + int(beta >= 0.9),
            "first_probe_time": self._grid_time(
                env,
                self._grid_index(last_idx, 0.18 + 0.10 * beta),
            ),
            "second_probe_time": self._grid_time(
                env,
                self._grid_index(last_idx, 0.50 + 0.18 * beta),
            ),
            "child_time": self._grid_time(
                env,
                self._grid_index(last_idx, 0.82 - 0.22 * beta),
            ),
            "branch_min_beta": 0.35,
            "branch_base": int(beta >= 0.35)
            + int(beta >= 0.75)
            + int(beta >= 0.95),
            "finish_base": 1 + int(beta >= 0.45) + int(beta >= 0.85),
            "keep_base": 1 + int(beta >= 0.40) + int(beta >= 0.80),
            "gap_threshold": 0.012 + 0.018 * beta,
            "noise_policy": "inferred_noise" if beta < 0.55 else "mixed_noise",
            "noise_strength": max(0.25, min(0.85, 0.84 - 0.44 * beta)),
        }

    def _keep_count(
        self,
        beta: float,
        ranked: list[PreviewRecord],
        schedule: dict[str, float | int],
    ) -> int:
        top_uncertainty = float(ranked[0].uncertainty or 0.0)
        keep = int(schedule["keep_base"])
        if top_uncertainty > 0.45 - 0.08 * beta:
            keep += 1
        if self._score_gap(ranked) <= float(schedule["gap_threshold"]):
            keep += 1
        return max(1, min(len(ranked), keep))

    def _finish_count(
        self,
        beta: float,
        ranked: list[PreviewRecord],
        schedule: dict[str, float | int],
    ) -> int:
        finish = int(schedule["finish_base"])
        if self._score_gap(ranked) <= float(schedule["gap_threshold"]):
            finish += 1
        if float(ranked[0].uncertainty or 0.0) > 0.50 - 0.10 * beta:
            finish += 1
        return max(1, min(len(ranked), finish))

    def _branch_and_refine(
        self,
        env: FlowTTSEnv,
        ranked: list[PreviewRecord],
        schedule: dict[str, float | int],
        beta: float,
    ) -> None:
        branch_count = int(schedule["branch_base"])
        if self._score_gap(ranked) <= float(schedule["gap_threshold"]):
            branch_count += 1
        branch_count = max(0, min(len(ranked), branch_count))
        if branch_count <= 0 or env.budget_left <= 0:
            return

        anchor_ids = [preview.id for preview in ranked[:branch_count]]
        extra_child = 1 if beta >= 0.9 and self._score_gap(ranked) <= float(schedule["gap_threshold"]) else 0
        for index, anchor_id in enumerate(anchor_ids):
            if env.budget_left <= 0:
                return
            num_children = 2 if index == 0 and extra_child else 1
            child_cost = self._estimate_finish_cost(env, schedule["child_time"]) + 1
            if env.budget_left < child_cost:
                return
            try:
                child_ids = env.backward(
                    anchor_id,
                    target_time=float(schedule["child_time"]),
                    noise_policy=str(schedule["noise_policy"]),
                    num_children=num_children,
                    strength=float(schedule["noise_strength"]),
                )
            except (BudgetExceededError, InvalidActionError):
                return
            self._finish_and_preview(env, child_ids)

    def _fallback_answer(self, env: FlowTTSEnv) -> AnswerRecord:
        state = env.get_state()
        if state.previews:
            return env.answer(rule="best_preview_score")
        return env.answer(rule="latest_active")

    def _finish_and_preview(self, env: FlowTTSEnv, particle_ids: list[int]) -> None:
        for particle_id in particle_ids:
            if not self._is_active(env, particle_id):
                if env.budget_left > 0:
                    try:
                        env.preview(particle_id, mode="clean_anchor", scorer="default")
                    except (BudgetExceededError, InvalidActionError):
                        return
                continue
            try:
                self._finish_to(env, particle_id, 1.0)
                if env.budget_left > 0:
                    env.preview(particle_id, mode="clean_anchor", scorer="default")
            except (BudgetExceededError, InvalidActionError):
                return

    def _advance_many(self, env: FlowTTSEnv, particle_ids: list[int], target_time: float) -> None:
        for particle_id in particle_ids:
            self._advance_to(env, particle_id, target_time)

    def _preview_many(self, env: FlowTTSEnv, particle_ids: list[int]) -> None:
        for particle_id in particle_ids:
            env.preview(particle_id, mode="clean_anchor", scorer="default")

    def _advance_to(self, env: FlowTTSEnv, particle_id: int, target_time: float) -> None:
        state = env.get_state()
        current_time = float(state.particles[particle_id].time)
        for grid_time in env.time_grid:
            if grid_time > current_time + 1e-9 and grid_time <= target_time + 1e-9:
                env.forward(particle_id, target_time=float(grid_time), solver="euler")
                current_time = float(grid_time)

    def _finish_to(self, env: FlowTTSEnv, particle_id: int, target_time: float) -> None:
        self._advance_to(env, particle_id, target_time)

    def _prune_active(
        self,
        env: FlowTTSEnv,
        particle_ids: list[int],
        keep_ids: set[int],
    ) -> None:
        losers = [
            particle_id
            for particle_id in particle_ids
            if particle_id not in keep_ids and self._is_active(env, particle_id)
        ]
        if losers:
            env.prune(losers)

    def _ranked_previews(self, env: FlowTTSEnv) -> list[PreviewRecord]:
        state = env.get_state()
        latest: dict[int, PreviewRecord] = {}
        for particle in state.particles.values():
            if particle.status == "pruned" or particle.last_preview_id is None:
                continue
            preview = state.previews.get(particle.last_preview_id)
            if preview is not None and preview.score is not None:
                latest[particle.id] = preview
        return sorted(
            latest.values(),
            key=lambda preview: (
                float(preview.score or float("-inf")),
                -float(preview.uncertainty or 0.0),
                float(preview.time),
            ),
            reverse=True,
        )

    def _score_gap(self, ranked: list[PreviewRecord]) -> float:
        if len(ranked) < 2:
            return float("inf")
        return float(ranked[0].score or 0.0) - float(ranked[1].score or 0.0)

    def _estimate_finish_cost(self, env: FlowTTSEnv, target_time: float) -> int:
        state = env.get_state()
        active = [particle for particle in state.particles.values() if particle.status == "active"]
        if not active:
            return 1
        current_time = min(float(particle.time) for particle in active)
        return max(1, self._steps_to(env, current_time, target_time))

    def _steps_to(self, env: FlowTTSEnv, start_time: float, target_time: float) -> int:
        return sum(1 for grid_time in env.time_grid if grid_time > start_time + 1e-9 and grid_time <= target_time + 1e-9)

    def _grid_index(self, last_idx: int, fraction: float) -> int:
        idx = int(round(last_idx * float(fraction)))
        return min(max(1, idx), last_idx)

    def _grid_time(self, env: FlowTTSEnv, index: int) -> float:
        index = min(max(0, int(index)), len(env.time_grid) - 1)
        return float(env.time_grid[index])

        prev_mean = sample * (1.0 + std_dev_t**2 / (2 * sigma) * dt) + model_output * (
            1.0 + std_dev_t**2 * (1.0 - sigma) / (2 * sigma)
        ) * dt
        step_std = std_dev_t * torch.sqrt(torch.clamp(-dt, min=0.0))
        next_latents = prev_mean + step_std * variance_noise
        return next_latents.detach(), float((step_std**2).mean().item())

    def _clean_and_noise_estimate(self, particle: _SD35Particle) -> tuple[Any, Any]:
        torch = self.resources.torch
        if particle.step_index >= self.config.num_steps:
            return particle.latents.detach(), torch.zeros_like(particle.latents)
        velocity = self._predict_velocity(particle.latents, particle.step_index)
        sigma = self._sigma(particle.step_index)
        clean = particle.latents.float() - sigma * velocity
        noise = particle.latents.float() + (1.0 - sigma) * velocity
        return clean.detach(), noise.detach()

    def _score_latents(self, latents: Any) -> tuple[float, dict[str, float]]:
        image = self._decode_latents(latents)
        score = float(self.resources.scorer([self.prompt], [image])[0])
        return score, {"pickscore": score}

    def _decode_latents(self, latents: Any) -> Any:
        torch = self.resources.torch
        pipe = self.resources.pipeline
        with torch.no_grad():
            vae_latents = (latents.float() / pipe.vae.config.scaling_factor) + pipe.vae.config.shift_factor
            vae_latents = vae_latents.to(device=self.resources.device, dtype=pipe.vae.dtype)
            image = pipe.vae.decode(vae_latents, return_dict=False)[0]
            return pipe.image_processor.postprocess(image, output_type="pil")[0]

    def _noise_for_policy(
        self,
        anchor: _SD35Anchor,
        noise_policy: str,
        strength: float,
        generator: Any,
    ) -> Any:
        if noise_policy == "inferred_noise":
            return anchor.noise_latents
        fresh = self._randn(anchor.clean_latents.shape, anchor.clean_latents.dtype, generator)
        if noise_policy == "fresh_noise":
            return fresh
        if noise_policy == "mixed_noise":
            lam = min(max(float(strength), 0.0), 1.0)
            return lam * anchor.noise_latents + (1.0 - lam) * fresh
        raise InvalidActionError(f"unsupported noise_policy: {noise_policy}")

    def _parse_sde_cfg(self, cfg: Any | None) -> dict[str, float | str]:
        if cfg is None:
            return {"noise_level": self.config.noise_level, "sde_type": self.config.sde_type}
        if isinstance(cfg, (int, float)):
            return {"noise_level": float(cfg), "sde_type": self.config.sde_type}
        if isinstance(cfg, dict):
            return {
                "noise_level": float(cfg.get("noise_level", cfg.get("noise_scale", self.config.noise_level))),
                "sde_type": str(cfg.get("sde_type", self.config.sde_type)),
            }
        raise InvalidActionError("SDE cfg must be None, a number, or a dict")

    def _sigma(self, step_index: int) -> Any:
        clamped = min(max(int(step_index), 0), self.config.num_steps)
        return self.resources.sigmas[clamped].to(device=self.resources.device, dtype=self.resources.torch.float32)

    def _time_to_step(self, target_time: float) -> int:
        time = min(max(float(target_time), 0.0), 1.0)
        return min(self.config.num_steps, max(0, math.ceil(time * self.config.num_steps - 1e-9)))

    def _time_to_step_floor(self, target_time: float) -> int:
        time = min(max(float(target_time), 0.0), 1.0)
        return min(self.config.num_steps, max(0, math.floor(time * self.config.num_steps + 1e-9)))

    def _step_to_time(self, step_index: int) -> float:
        return float(step_index) / float(self.config.num_steps)

    def _preview_uncertainty(self, step_index: int, sde_variance: float) -> float:
        base = 1.0 - self._step_to_time(step_index)
        stochastic = math.sqrt(max(0.0, float(sde_variance)))
        return max(0.0, min(1.0, base + 0.25 * stochastic))

    def _latent_rmse(self, a: Any, b: Any) -> float:
        return float((a.float() - b.float()).pow(2).mean().sqrt().detach().cpu().item())

    def _make_generator(self, seed: int) -> Any:
        torch = self.resources.torch
        try:
            generator = torch.Generator(device=self.resources.device)
        except RuntimeError:
            generator = torch.Generator()
        return generator.manual_seed(int(seed) % (2**31 - 1))

    def _randn(self, shape: Any, dtype: Any, generator: Any) -> Any:
        torch = self.resources.torch
        return torch.randn(
            shape,
            generator=generator,
            device=self.resources.device,
            dtype=dtype,
        )

    def _require_particle(self, particle_id: int, status: str | None = None) -> _SD35Particle:
        try:
            particle = self._particles[int(particle_id)]
        except KeyError as exc:
            raise InvalidActionError(f"unknown particle_id: {particle_id}") from exc
        if status is not None and particle.status != status:
            raise InvalidActionError(
                f"particle {particle_id} has status {particle.status}, expected {status}"
            )
        return particle

    def _require_anchor(self, anchor_id: int) -> _SD35Anchor:
        try:
            return self._anchors[int(anchor_id)]
        except KeyError as exc:
            raise InvalidActionError(f"unknown anchor_id: {anchor_id}") from exc

    def _charge(self, nfe_cost: int) -> None:
        if self._nfe_used + int(nfe_cost) > self.budget:
            raise BudgetExceededError(
                f"action would exceed budget: used {self._nfe_used}, "
                f"cost {nfe_cost}, budget {self.budget}"
            )
        self._nfe_used += int(nfe_cost)

    def _log(
        self,
        action: str,
        particle_ids: list[int],
        input_time: float | None,
        output_time: float | None,
        nfe_cost: int,
        details: dict[str, Any],
    ) -> None:
        self._events.append(
            EventRecord(
                step_id=len(self._events),
                action=action,
                particle_ids=list(particle_ids),
                input_time=input_time,
                output_time=output_time,
                nfe_cost=int(nfe_cost),
                budget_left=self.budget_left,
                details=dict(details),
            )
        )

    def _status_lists(self) -> tuple[list[int], list[int], list[int]]:
        active: list[int] = []
        completed: list[int] = []
        pruned: list[int] = []
        for particle_id, particle in self._particles.items():
            if particle.status == "active":
                active.append(particle_id)
            elif particle.status == "completed":
                completed.append(particle_id)
            elif particle.status == "pruned":
                pruned.append(particle_id)
        return active, completed, pruned

    def _ensure_open(self) -> None:
        if self._answered:
            raise InvalidActionError("episode already answered")


def _torch_dtype(torch: object, dtype: str):
    normalized = str(dtype).lower()
    if normalized in {"fp16", "float16", "half"}:
        return torch.float16
    if normalized in {"bf16", "bfloat16"}:
        return torch.bfloat16
    if normalized in {"fp32", "float32", "no"}:
        return torch.float32
    raise ValueError(f"unsupported dtype: {dtype}")


def _move_text_encoders(pipeline: Any, device: str) -> None:
    for name in ("text_encoder", "text_encoder_2", "text_encoder_3"):
        encoder = getattr(pipeline, name, None)
        if encoder is not None:
            encoder.to(device)

"""Candidate controller for SD3.5 PickScore discovery."""

from __future__ import annotations

from flow_autotts.core.env import FlowTTSEnv
from flow_autotts.core.errors import BudgetExceededError, InvalidActionError
from flow_autotts.core.state import AnswerRecord, PreviewRecord


class OptimalController:
    """Completed-anchor best-of-N with beta-scaled late refinement."""

    def solve(self, env: FlowTTSEnv, beta: float) -> AnswerRecord:
        beta = min(max(float(beta), 0.0), 1.0)
        initial_budget = max(0, int(env.budget_left))

        root_id = env.spawn(1)[0]
        try:
            self._finish(env, root_id)
        except BudgetExceededError:
            return env.answer(rule="latest_active")

        if beta <= 0.0 or env.budget_left <= 0:
            return env.answer(rule="latest_active")

        target_nfe = self._target_nfe(initial_budget, beta, spent=initial_budget - env.budget_left)
        self._preview(env, root_id, target_nfe, initial_budget)

        step_count = max(1, len(env.time_grid) - 1)
        full_candidate_cost = step_count + 1
        full_candidates = max(1, min(5, 1 + int(4 * beta), target_nfe // full_candidate_cost))
        extra_roots = max(0, full_candidates - 1)
        if extra_roots > 0:
            for particle_id in env.spawn(extra_roots):
                if self._spent(env, initial_budget) + full_candidate_cost > target_nfe:
                    break
                try:
                    self._finish(env, particle_id)
                    self._preview(env, particle_id, target_nfe, initial_budget)
                except (BudgetExceededError, InvalidActionError):
                    break

        self._refine_from_best_previews(env, beta, target_nfe, initial_budget)
        return env.answer(rule="best_preview_score")

    def _target_nfe(self, initial_budget: int, beta: float, spent: int) -> int:
        if initial_budget <= spent:
            return spent
        extra = int((initial_budget - spent) * beta)
        if beta > 0.0:
            extra = max(1, extra)
        return min(initial_budget, spent + extra)

    def _finish(self, env: FlowTTSEnv, particle_id: int) -> None:
        state = env.get_state()
        current_time = state.particles[particle_id].time
        for target_time in env.time_grid:
            if target_time > current_time:
                env.forward(particle_id, target_time=target_time, solver="euler")
                current_time = target_time

    def _preview(
        self,
        env: FlowTTSEnv,
        particle_id: int,
        target_nfe: int,
        initial_budget: int,
    ) -> None:
        if self._spent(env, initial_budget) + 1 <= target_nfe and env.budget_left > 0:
            env.preview(particle_id, mode="clean_anchor", scorer="default")

    def _refine_from_best_previews(
        self,
        env: FlowTTSEnv,
        beta: float,
        target_nfe: int,
        initial_budget: int,
    ) -> None:
        target_time = self._backward_time(beta)
        noise_policy = "mixed_noise" if beta >= 0.6 else "fresh_noise"
        strength = 0.35 if noise_policy == "mixed_noise" else 1.0
        max_children = max(0, int(1 + 4 * beta))

        children_made = 0
        while children_made < max_children:
            previews = self._ranked_previews(env)
            if not previews:
                return
            anchor = previews[children_made % len(previews)]
            child_cost = self._child_finish_preview_cost(env, target_time)
            if self._spent(env, initial_budget) + child_cost > target_nfe:
                return
            try:
                child_id = env.backward(
                    anchor.id,
                    target_time=target_time,
                    noise_policy=noise_policy,
                    num_children=1,
                    strength=strength,
                )[0]
                self._finish(env, child_id)
                self._preview(env, child_id, target_nfe, initial_budget)
            except (BudgetExceededError, InvalidActionError):
                return
            children_made += 1

    def _ranked_previews(self, env: FlowTTSEnv) -> list[PreviewRecord]:
        state = env.get_state()
        previews = [
            preview
            for preview in state.previews.values()
            if preview.score is not None
            and preview.particle_id in state.particles
            and state.particles[preview.particle_id].status != "pruned"
        ]
        return sorted(
            previews,
            key=lambda preview: (
                float(preview.score),
                -float(preview.uncertainty or 0.0),
                float(preview.time),
            ),
            reverse=True,
        )

    def _child_finish_preview_cost(self, env: FlowTTSEnv, target_time: float) -> int:
        forward_steps = sum(1 for time in env.time_grid if time > target_time)
        return max(1, forward_steps) + 1

    def _backward_time(self, beta: float) -> float:
        if beta >= 0.8:
            return 0.65
        if beta >= 0.5:
            return 0.75
        return 0.85

    def _spent(self, env: FlowTTSEnv, initial_budget: int) -> int:
        return max(0, int(initial_budget - env.budget_left))

"""Candidate controller for SD3.5 PickScore discovery."""

from __future__ import annotations

from flow_autotts.core.env import FlowTTSEnv
from flow_autotts.core.errors import BudgetExceededError, InvalidActionError
from flow_autotts.core.state import AnswerRecord, PreviewRecord


class OptimalController:
    """Preview-gated multi-root scout and refine controller."""

    def solve(self, env: FlowTTSEnv, beta: float) -> AnswerRecord:
        beta = min(max(float(beta), 0.0), 1.0)
        initial_budget = max(0, int(env.budget_left))

        try:
            schedule = self._schedule(beta, env)
            if beta <= 0.0:
                root_id = env.spawn(1)[0]
                self._finish(env, root_id)
                return env.answer(rule="latest_active")

            root_ids = env.spawn(max(1, int(schedule["scouts"])))
            self._advance_batch(env, root_ids, float(schedule["scout_time"]))
            self._preview_batch(env, root_ids)
            ranked = self._ranked_previews(env)
            if not ranked:
                return self._fallback_answer(env)

            keep_ids = self._select_keep_ids(ranked, schedule)
            self._prune_roots(env, root_ids, keep_ids)

            if float(schedule["confirm_time"]) > float(schedule["scout_time"]):
                confirm_ids = self._confirm_roots(env, keep_ids, float(schedule["confirm_time"]))
                self._preview_batch(env, confirm_ids)
                ranked = self._ranked_previews(env)
                if not ranked:
                    return self._fallback_answer(env)

            if env.budget_left <= 0:
                return env.answer(rule="best_preview_score")

            self._branch_and_refine(env, ranked, schedule, beta)

            if beta >= 0.85 and env.budget_left > 0:
                self._late_verify(env, ranked, schedule)

        except (BudgetExceededError, InvalidActionError):
            return env.answer(rule="latest_active")

        return env.answer(rule="best_preview_score")

    def _schedule(self, beta: float, env: FlowTTSEnv) -> dict[str, float | int]:
        grid_last = max(1, len(env.time_grid) - 1)
        scout_stage = self._grid_time(env, self._grid_index(grid_last, 0.14 + 0.12 * beta))
        confirm_stage = self._grid_time(env, self._grid_index(grid_last, 0.48 + 0.20 * beta))
        branch_stage = self._grid_time(env, self._grid_index(grid_last, 0.70 + 0.18 * beta))
        finish_stage = self._grid_time(env, self._grid_index(grid_last, 0.88 + 0.08 * beta))

        scouts = 1 + int(beta > 0.0) + int(beta >= 0.25) + int(beta >= 0.55) + int(beta >= 0.85)
        keep_base = 1 + int(beta >= 0.45) + int(beta >= 0.80)
        branch_base = 0
        if beta >= 0.35:
            branch_base += 1
        if beta >= 0.70:
            branch_base += 1
        if beta >= 0.92:
            branch_base += 1

        return {
            "scouts": scouts,
            "scout_time": scout_stage,
            "confirm_time": confirm_stage,
            "branch_time": branch_stage,
            "finish_time": finish_stage,
            "keep_base": keep_base,
            "branch_base": branch_base,
            "score_gap": 0.010 + 0.016 * beta,
            "uncertainty": 0.44 - 0.10 * beta,
            "children": 1 + int(beta >= 0.45) + int(beta >= 0.80),
            "noise_policy": "inferred_noise" if beta < 0.55 else "mixed_noise",
            "noise_strength": 0.78 - 0.32 * beta,
            "confirm_children": 1 + int(beta >= 0.90),
        }

    def _finish(self, env: FlowTTSEnv, particle_id: int) -> None:
        state = env.get_state()
        current_time = state.particles[particle_id].time
        for target_time in env.time_grid:
            if target_time > current_time:
                env.forward(particle_id, target_time=target_time, solver="euler")
                current_time = target_time

    def _advance_batch(self, env: FlowTTSEnv, particle_ids: list[int], target_time: float) -> None:
        for particle_id in particle_ids:
            self._advance_to(env, particle_id, target_time)

    def _preview_batch(self, env: FlowTTSEnv, particle_ids: list[int]) -> None:
        for particle_id in particle_ids:
            if env.budget_left <= 0:
                return
            env.preview(particle_id, mode="clean_anchor", scorer="default")

    def _select_keep_ids(
        self,
        ranked: list[PreviewRecord],
        schedule: dict[str, float | int],
    ) -> set[int]:
        keep = int(schedule["keep_base"])
        if self._score_gap(ranked) <= float(schedule["score_gap"]):
            keep += 1
        if float(ranked[0].uncertainty or 0.0) >= float(schedule["uncertainty"]):
            keep += 1
        keep = max(1, min(len(ranked), keep))
        return {preview.particle_id for preview in ranked[:keep]}

    def _prune_roots(self, env: FlowTTSEnv, root_ids: list[int], keep_ids: set[int]) -> None:
        losers = [particle_id for particle_id in root_ids if particle_id not in keep_ids]
        if losers:
            env.prune(losers)

    def _confirm_roots(self, env: FlowTTSEnv, keep_ids: set[int], target_time: float) -> list[int]:
        confirmed: list[int] = []
        for particle_id in list(keep_ids):
            if env.budget_left <= 0:
                break
            try:
                self._advance_to(env, particle_id, target_time)
                confirmed.append(particle_id)
            except (BudgetExceededError, InvalidActionError):
                continue
        return confirmed

    def _branch_and_refine(
        self,
        env: FlowTTSEnv,
        ranked: list[PreviewRecord],
        schedule: dict[str, float | int],
        beta: float,
    ) -> None:
        branch_count = int(schedule["branch_base"])
        if self._score_gap(ranked) <= float(schedule["score_gap"]):
            branch_count += 1
        if float(ranked[0].uncertainty or 0.0) >= float(schedule["uncertainty"]):
            branch_count += 1
        branch_count = max(0, min(len(ranked), branch_count))
        if branch_count <= 0:
            return

        branch_ids = [preview.id for preview in ranked[:branch_count]]
        target_time = float(schedule["branch_time"])
        finish_time = float(schedule["finish_time"])
        for index, anchor_id in enumerate(branch_ids):
            if env.budget_left <= 0:
                return
            num_children = int(schedule["children"])
            if index > 0 and beta < 0.75:
                num_children = 1
            if index == 0 and beta >= 0.9 and self._score_gap(ranked) <= float(schedule["score_gap"]):
                num_children += 1
            try:
                child_ids = env.backward(
                    anchor_id,
                    target_time=target_time,
                    noise_policy=str(schedule["noise_policy"]),
                    num_children=num_children,
                    strength=float(schedule["noise_strength"]),
                )
            except (BudgetExceededError, InvalidActionError):
                return

            for child_id in child_ids:
                if env.budget_left <= 0:
                    return
                try:
                    self._advance_to(env, child_id, finish_time)
                    env.preview(child_id, mode="clean_anchor", scorer="default")
                except (BudgetExceededError, InvalidActionError):
                    return

    def _late_verify(
        self,
        env: FlowTTSEnv,
        ranked: list[PreviewRecord],
        schedule: dict[str, float | int],
    ) -> None:
        if not ranked or env.budget_left <= 0:
            return
        top = ranked[0]
        if self._score_gap(ranked) > float(schedule["score_gap"]) and float(top.uncertainty or 0.0) < float(schedule["uncertainty"]):
            return
        try:
            child_ids = env.backward(
                top.id,
                target_time=float(schedule["branch_time"]),
                noise_policy="mixed_noise",
                num_children=int(schedule["confirm_children"]),
                strength=max(0.2, float(schedule["noise_strength"]) * 0.75),
            )
        except (BudgetExceededError, InvalidActionError):
            return
        for child_id in child_ids:
            if env.budget_left <= 0:
                return
            try:
                self._advance_to(env, child_id, float(schedule["finish_time"]))
                env.preview(child_id, mode="clean_anchor", scorer="default")
            except (BudgetExceededError, InvalidActionError):
                return

    def _advance_to(self, env: FlowTTSEnv, particle_id: int, target_time: float) -> None:
        state = env.get_state()
        current_time = float(state.particles[particle_id].time)
        for grid_time in env.time_grid:
            if grid_time > current_time + 1e-9 and grid_time <= target_time + 1e-9:
                env.forward(particle_id, target_time=float(grid_time), solver="euler")
                current_time = float(grid_time)

    def _ranked_previews(self, env: FlowTTSEnv) -> list[PreviewRecord]:
        state = env.get_state()
        previews: dict[int, PreviewRecord] = {}
        for particle in state.particles.values():
            if particle.status == "pruned" or particle.last_preview_id is None:
                continue
            preview = state.previews.get(particle.last_preview_id)
            if preview is None or preview.score is None:
                continue
            previews[particle.id] = preview
        return sorted(
            previews.values(),
            key=lambda preview: (
                float(preview.score),
                -float(preview.uncertainty or 0.0),
                float(preview.time),
            ),
            reverse=True,
        )

    def _score_gap(self, ranked: list[PreviewRecord]) -> float:
        if len(ranked) < 2:
            return float("inf")
        return float(ranked[0].score or 0.0) - float(ranked[1].score or 0.0)

    def _fallback_answer(self, env: FlowTTSEnv) -> AnswerRecord:
        state = env.get_state()
        if state.previews:
            return env.answer(rule="best_preview_score")
        return env.answer(rule="latest_active")

    def _grid_index(self, last_idx: int, fraction: float) -> int:
        idx = int(round(last_idx * float(fraction)))
        return min(max(1, idx), last_idx)

    def _grid_time(self, env: FlowTTSEnv, index: int) -> float:
        index = min(max(0, int(index)), len(env.time_grid) - 1)
